)

// SandboxManager manages the lifecycle of sandboxes on a worker.
// ---------------------------------------------
// pkg/worker/sandbox.go
//
// type struct SandboxManager                L61
// type struct Sandbox                       L86
// type struct Config                        L98
// func NewSandboxManager()                 L131
// func coalesce()                          L218
//   func publishStatus()                   L225
